import React from "react";
import {reduxForm} from "redux-form";
import {createField} from "../../Common/FormsControls/FormsControls";

const ProfileDataForm = ({handleSubmit}) => {
    return <form onSubmit={handleSubmit}>
        <div>
            <button>Save</button>
        </div>
        {/*<ul className={classes.profiletext}>*/}
            <div><b>Полное имя:</b> {createField('Input', 'Full Name', 'fullName', 'text', [])} </div>
        <div><b>О себе:</b>
            {createField('Textarea', 'About My', 'aboutMe', 'textarea', [])}
            </div>
                   {/*<li><b>Мои контакты:</b></li>*/}
            {/*<div>*/}
            {/*    <b>Contacts</b>: {Object.keys(profile.contacts).map(key => {*/}
            {/*    return <Contact key={key} contactTitle={key} contactValue={profile.contacts[key]}/>*/}
            {/*})}*/}
            {/*</div>*/}
            <div><b>В поиске работы?</b>
                {createField('Input', '', 'lookingForAJob', 'checkbox', [])}
                {/*{createField('Input', '', 'lookingForAJob', 'radio', [])}*/}
                {/*{createField('Input', '', 'lookingForAJob', 'radio', [])}*/}
            </div>
        {/*        <img src={profile.lookingForAJob ? yesLogo : noLogo}*/}
        {/*             alt={'AnswerLogo'}/></li>*/}
        <div><b> Професииональный опыт (описание поиска работы):</b>
        {createField('Input', 'My professional skills', 'lookingForAJobDescription', 'text', [])}
        </div>
    </form>
}

const ProfileDataFormReduxForm = reduxForm({
    form: 'edit-profile'
}) (ProfileDataForm)

export default ProfileDataFormReduxForm;
